(function () {
	"use strict";

	angular.module("ariaNg").controller("CommandController", [
		"$rootScope",
		"$window",
		"$location",
		"$routeParams",
		"ariaNgDefaultOptions",
		"ariaNgCommonService",
		"ariaNgLogService",
		"ariaNgSettingService",
		"aria2TaskService",
		"aria2SettingService",
		function (
			$rootScope,
			$window,
			$location,
			$routeParams,
			ariaNgDefaultOptions,
			ariaNgCommonService,
			ariaNgLogService,
			ariaNgSettingService,
			aria2TaskService,
			aria2SettingService
		) {
			var path = $location.path();

			var doNewTaskCommand = function (url, params) {
				try {
					url = ariaNgCommonService.base64UrlDecode(url);
				} catch (ex) {
					ariaNgCommonService.showError("URL is not base64 encoded!");
					return false;
				}

				var options = {};
				var isPaused = false;

				if (params) {
					for (var key in params) {
						if (!params.hasOwnProperty(key)) {
							continue;
						}

						if (aria2SettingService.isOptionKeyValid(key)) {
							options[key] = params[key];
						}
					}

					if (params.pause === "true") {
						isPaused = true;
					}
				}

				$rootScope.loadPromise = aria2TaskService.newUriTask(
					{
						urls: [url],
						options: options,
					},
					isPaused,
					function (response) {
						if (!response.success) {
							return false;
						}

						if (isPaused) {
							$location.path("/waiting");
						} else {
							$location.path("/downloading");
						}
					}
				);

				ariaNgLogService.info("[CommandController] new download: " + url);

				return true;
			};

			var doSetRpcCommand = function (
				rpcProtocol,
				rpcHost,
				rpcPort,
				rpcInterface,
				secret
			) {
				rpcPort = rpcPort || ariaNgDefaultOptions.rpcPort;
				rpcInterface = rpcInterface || ariaNgDefaultOptions.rpcInterface;
				secret = secret || ariaNgDefaultOptions.secret;

				ariaNgLogService.info(
					"[CommandController] set rpc: " +
						rpcProtocol +
						"://" +
						rpcHost +
						":" +
						rpcPort +
						"/" +
						rpcInterface +
						", secret: " +
						secret
				);

				if (
					!rpcProtocol ||
					(rpcProtocol !== "http" &&
						rpcProtocol !== "https" &&
						rpcProtocol !== "ws" &&
						rpcProtocol !== "wss")
				) {
					ariaNgCommonService.showError("Protocol is invalid!");
					return false;
				}

				if (!rpcHost) {
					ariaNgCommonService.showError("RPC host cannot be empty!");
					return false;
				}

				if (secret) {
					try {
						secret = ariaNgCommonService.base64UrlDecode(secret);
					} catch (ex) {
						ariaNgCommonService.showError("RPC secret is not base64 encoded!");
						return false;
					}
				}

				var newSetting = {
					rpcAlias: "",
					rpcHost: rpcHost,
					rpcPort: rpcPort,
					rpcInterface: rpcInterface,
					protocol: rpcProtocol,
					httpMethod: ariaNgDefaultOptions.httpMethod,
					rpcRequestHeaders: "",
					secret: secret,
				};

				if (ariaNgSettingService.isRpcSettingEqualsDefault(newSetting)) {
					$location.path("/downloading");
				} else {
					ariaNgSettingService.setDefaultRpcSetting(newSetting, {
						keepCurrent: false,
						forceSet: true,
					});

					$location.path("/downloading");
					$window.location.reload();
				}

				return true;
			};

			var doCommand = function (path, params) {
				if (path.indexOf("/new") === 0) {
					return doNewTaskCommand(params.url, params);
				} else if (path.indexOf("/settings/rpc/set") === 0) {
					return doSetRpcCommand(
						params.protocol,
						params.host,
						params.port,
						params.interface,
						params.secret
					);
				} else {
					ariaNgCommonService.showError("Parameter is invalid!");
					return false;
				}
			};

			var allParameters = angular.extend({}, $routeParams, $location.search());

			if (!doCommand(path, allParameters)) {
				$location.path("/downloading");
			}
		},
	]);
})();

(function () {
	"use strict";

	angular.module("ariaNg").controller("AriaNgDebugController", [
		"$rootScope",
		"$scope",
		"$location",
		"$interval",
		"$timeout",
		"$filter",
		"ariaNgConstants",
		"ariaNgCommonService",
		"ariaNgLocalizationService",
		"ariaNgLogService",
		"ariaNgKeyboardService",
		"ariaNgSettingService",
		"aria2RpcService",
		function (
			$rootScope,
			$scope,
			$location,
			$interval,
			$timeout,
			$filter,
			ariaNgConstants,
			ariaNgCommonService,
			ariaNgLocalizationService,
			ariaNgLogService,
			ariaNgKeyboardService,
			ariaNgSettingService,
			aria2RpcService
		) {
			var tabStatusItems = [
				{
					name: "logs",
					show: true,
				},
				{
					name: "rpc",
					show: true,
				},
			];
			var debugLogRefreshPromise = null;

			var getVisibleTabOrders = function () {
				var items = [];

				for (var i = 0; i < tabStatusItems.length; i++) {
					if (tabStatusItems[i].show) {
						items.push(tabStatusItems[i].name);
					}
				}

				return items;
			};

			var loadAria2RPCMethods = function () {
				if (
					$scope.context.availableRpcMethods &&
					$scope.context.availableRpcMethods.length
				) {
					return;
				}

				return aria2RpcService.listMethods({
					silent: false,
					callback: function (response) {
						if (response.success) {
							$scope.context.availableRpcMethods = response.data;
						}
					},
				});
			};

			$scope.context = {
				currentTab: "logs",
				logMaxCount: ariaNgConstants.cachedDebugLogsLimit,
				logAutoRefreshAvailableInterval: ariaNgCommonService.getTimeOptions(
					[100, 200, 500, 1000, 2000],
					true
				),
				logAutoRefreshInterval: 1000,
				logListDisplayOrder: "time:desc",
				logLevelFilter: "DEBUG",
				logs: [],
				currentLog: null,
				availableRpcMethods: [],
				rpcRequestMethod: "",
				rpcRequestParameters: "{}",
				rpcResponse: null,
			};

			$scope.enableDebugMode = function () {
				return ariaNgSettingService.isEnableDebugMode();
			};

			$scope.changeTab = function (tabName) {
				if (tabName === "rpc") {
					$rootScope.loadPromise = loadAria2RPCMethods();
				}

				$scope.context.currentTab = tabName;
			};

			$scope.changeLogListDisplayOrder = function (type) {
				var oldType = ariaNgCommonService.parseOrderType(
					$scope.context.logListDisplayOrder
				);
				var newType = ariaNgCommonService.parseOrderType(type);

				if (newType.type === oldType.type) {
					newType.reverse = !oldType.reverse;
				}

				$scope.context.logListDisplayOrder = newType.getValue();
			};

			$scope.isLogListSetDisplayOrder = function (type) {
				var orderType = ariaNgCommonService.parseOrderType(
					$scope.context.logListDisplayOrder
				);
				var targetType = ariaNgCommonService.parseOrderType(type);

				return orderType.equals(targetType);
			};

			$scope.getLogListOrderType = function () {
				return $scope.context.logListDisplayOrder;
			};

			$scope.filterLog = function (log) {
				if (!log || !angular.isString(log.level)) {
					return false;
				}

				if (!$scope.context.logLevelFilter) {
					return true;
				}

				return (
					ariaNgLogService.compareLogLevel(
						log.level,
						$scope.context.logLevelFilter
					) >= 0
				);
			};

			$scope.setLogLevelFilter = function (filter) {
				$scope.context.logLevelFilter = filter;
			};

			$scope.isSetLogLevelFilter = function (filter) {
				return $scope.context.logLevelFilter === filter;
			};

			$scope.getLogLevelFilter = function () {
				return $scope.context.logLevelFilter;
			};

			$scope.setAutoRefreshInterval = function (interval) {
				$scope.context.logAutoRefreshInterval = interval;

				if (debugLogRefreshPromise) {
					$interval.cancel(debugLogRefreshPromise);
				}

				if (interval > 0) {
					$scope.reloadLogs();

					debugLogRefreshPromise = $interval(function () {
						$scope.reloadLogs();
					}, $scope.context.logAutoRefreshInterval);
				}
			};

			$scope.reloadLogs = function () {
				$scope.context.logs = ariaNgLogService.getDebugLogs().slice();
			};

			$scope.clearDebugLogs = function () {
				ariaNgCommonService.confirm(
					"Confirm Clear",
					"Are you sure you want to clear debug logs?",
					"warning",
					function () {
						ariaNgLogService.clearDebugLogs();
						$scope.reloadLogs();
					},
					false
				);
			};

			$scope.showLogDetail = function (log) {
				$scope.context.currentLog = log;
				angular.element("#log-detail-modal").modal();
			};

			$("#log-detail-modal").on("hide.bs.modal", function (e) {
				$scope.context.currentLog = null;
			});

			$scope.executeAria2Method = function () {
				if (
					!$scope.context.rpcRequestMethod ||
					$scope.context.rpcRequestMethod.indexOf(".") < 0
				) {
					ariaNgCommonService.showError("RPC method is illegal!");
					return;
				}

				var methodNameParts = $scope.context.rpcRequestMethod.split(".");

				if (methodNameParts.length !== 2) {
					ariaNgCommonService.showError("RPC method is illegal!");
					return;
				}

				var methodName = methodNameParts[1];

				if (!angular.isFunction(aria2RpcService[methodName])) {
					ariaNgCommonService.showError(
						"AriaNg does not support this RPC method!"
					);
					return;
				}

				var context = {
					silent: false,
					callback: function (response) {
						if (response) {
							$scope.context.rpcResponse = $filter("json")(response.data);
						} else {
							$scope.context.rpcResponse = $filter("json")(response);
						}
					},
				};

				var parameters = {};

				try {
					parameters = angular.fromJson($scope.context.rpcRequestParameters);
				} catch (ex) {
					ariaNgLogService.error(
						"[AriaNgDebugController.executeAria2Method] failed to parse request parameters: " +
							$scope.context.rpcRequestParameters,
						ex
					);
					ariaNgCommonService.showError("RPC request parameters are invalid!");
					return;
				}

				for (var key in parameters) {
					if (
						!parameters.hasOwnProperty(key) ||
						key === "silent" ||
						key === "callback"
					) {
						continue;
					}

					context[key] = parameters[key];
				}

				return aria2RpcService[methodName](context);
			};

			$scope.requestParametersTextboxKeyDown = function (event) {
				if (!ariaNgSettingService.getKeyboardShortcuts()) {
					return;
				}

				if (
					ariaNgKeyboardService.isCtrlEnterPressed(event) &&
					$scope.executeMethodForm.$valid
				) {
					if (event.preventDefault) {
						event.preventDefault();
					}

					$scope.executeAria2Method();

					return false;
				}
			};

			$scope.$on("$destroy", function () {
				if (debugLogRefreshPromise) {
					$interval.cancel(debugLogRefreshPromise);
				}
			});

			$rootScope.swipeActions.extendLeftSwipe = function () {
				var tabItems = getVisibleTabOrders();
				var tabIndex = tabItems.indexOf($scope.context.currentTab);

				if (tabIndex < tabItems.length - 1) {
					$scope.changeTab(tabItems[tabIndex + 1]);
					return true;
				} else {
					return false;
				}
			};

			$rootScope.swipeActions.extendRightSwipe = function () {
				var tabItems = getVisibleTabOrders();
				var tabIndex = tabItems.indexOf($scope.context.currentTab);

				if (tabIndex > 0) {
					$scope.changeTab(tabItems[tabIndex - 1]);
					return true;
				} else {
					return false;
				}
			};

			$rootScope.loadPromise = $timeout(function () {
				if (!ariaNgSettingService.isEnableDebugMode()) {
					ariaNgCommonService.showError("Access Denied!", function () {
						if (!ariaNgSettingService.isEnableDebugMode()) {
							$location.path("/settings/ariang");
						}
					});
					return;
				}

				$scope.setAutoRefreshInterval($scope.context.logAutoRefreshInterval);
			}, 100);
		},
	]);
})();

(function () {
	"use strict";

	angular.module("ariaNg").controller("MainController", [
		"$rootScope",
		"$scope",
		"$route",
		"$window",
		"$location",
		"$document",
		"$interval",
		"clipboard",
		"aria2RpcErrors",
		"ariaNgCommonService",
		"ariaNgVersionService",
		"ariaNgNotificationService",
		"ariaNgSettingService",
		"ariaNgMonitorService",
		"ariaNgTitleService",
		"aria2TaskService",
		"aria2SettingService",
		function (
			$rootScope,
			$scope,
			$route,
			$window,
			$location,
			$document,
			$interval,
			clipboard,
			aria2RpcErrors,
			ariaNgCommonService,
			ariaNgVersionService,
			ariaNgNotificationService,
			ariaNgSettingService,
			ariaNgMonitorService,
			ariaNgTitleService,
			aria2TaskService,
			aria2SettingService,
		) {
			var pageTitleRefreshPromise = null;
			var globalStatRefreshPromise = null;

			var getTaskListPageType = function () {
				var location = $location.path().substring(1);

				if (
					location === "downloading" ||
					location === "waiting" ||
					location === "stopped"
				) {
					return location;
				} else {
					return "";
				}
			};

			var refreshPageTitle = function () {
				var title = ariaNgTitleService.getFinalTitleByGlobalStat({
					globalStat: $scope.globalStat,
					currentRpcProfile: getCurrentRPCProfile(),
				});

				$document[0].title = title;
			};

			var refreshGlobalStat = function (silent, callback) {
				return aria2SettingService.getGlobalStat(function (response) {
					if (
						!response.success &&
						response.data.message === aria2RpcErrors.Unauthorized.message
					) {
						$interval.cancel(globalStatRefreshPromise);
						return;
					}

					if (response.success) {
						$scope.globalStat = response.data;
						ariaNgMonitorService.recordGlobalStat(response.data);
					}

					if (callback) {
						callback(response);
					}
				}, silent);
			};

			var getCurrentRPCProfile = function () {
				if (!$scope.rpcSettings || $scope.rpcSettings.length < 1) {
					return null;
				}

				for (var i = 0; i < $scope.rpcSettings.length; i++) {
					var rpcSetting = $scope.rpcSettings[i];
					if (rpcSetting.isDefault) {
						return rpcSetting;
					}
				}

				return null;
			};

			if (ariaNgSettingService.getBrowserNotification()) {
				ariaNgNotificationService.requestBrowserPermission();
			}

			$scope.ariaNgVersion = ariaNgVersionService.getBuildVersion();

			$scope.globalStatusContext = {
				isEnabled: ariaNgSettingService.getGlobalStatRefreshInterval() > 0,
				data: ariaNgMonitorService.getGlobalStatsData(),
			};

			$scope.enableDebugMode = function () {
				return ariaNgSettingService.isEnableDebugMode();
			};

			$scope.quickSettingContext = null;

			$scope.rpcSettings = ariaNgSettingService.getAllRpcSettings();
			$scope.currentRpcProfile = getCurrentRPCProfile();
			$scope.isCurrentRpcUseWebSocket =
				ariaNgSettingService.isCurrentRpcUseWebSocket();

			$scope.isTaskSelected = function () {
				return $rootScope.taskContext.getSelectedTaskIds().length > 0;
			};

			$scope.isSelectedTasksAllHaveUrl = function () {
				var selectedTasks = $rootScope.taskContext.getSelectedTasks();

				if (selectedTasks.length < 1) {
					return false;
				}

				for (var i = 0; i < selectedTasks.length; i++) {
					if (!selectedTasks[i].singleUrl) {
						return false;
					}
				}

				return true;
			};

			$scope.isSelectedTasksAllHaveInfoHash = function () {
				var selectedTasks = $rootScope.taskContext.getSelectedTasks();

				if (selectedTasks.length < 1) {
					return false;
				}

				for (var i = 0; i < selectedTasks.length; i++) {
					if (!selectedTasks[i].bittorrent || !selectedTasks[i].infoHash) {
						return false;
					}
				}

				return true;
			};

			$scope.isSpecifiedTaskSelected = function () {
				var selectedTasks = $rootScope.taskContext.getSelectedTasks();

				if (selectedTasks.length < 1) {
					return false;
				}

				for (var i = 0; i < selectedTasks.length; i++) {
					for (var j = 0; j < arguments.length; j++) {
						if (selectedTasks[i].status === arguments[j]) {
							return true;
						}
					}
				}

				return false;
			};

			$scope.isSpecifiedTaskShowing = function () {
				var tasks = $rootScope.taskContext.list;

				if (tasks.length < 1) {
					return false;
				}

				for (var i = 0; i < tasks.length; i++) {
					for (var j = 0; j < arguments.length; j++) {
						if (tasks[i].status === arguments[j]) {
							return true;
						}
					}
				}

				return false;
			};

			$scope.changeTasksState = function (state) {
				var gids = $rootScope.taskContext.getSelectedTaskIds();

				if (!gids || gids.length < 1) {
					return;
				}

				var invoke = null;

				if (state === "start") {
					invoke = aria2TaskService.startTasks;
				} else if (state === "pause") {
					invoke = aria2TaskService.pauseTasks;
				} else {
					return;
				}

				$rootScope.loadPromise = invoke(
					gids,
					function (response) {
						if (response.hasError && gids.length > 1) {
							ariaNgCommonService.showError(
								"Failed to change some tasks state.",
							);
						}

						if (!response.hasSuccess) {
							return;
						}

						refreshGlobalStat(true);

						if (!response.hasError && state === "start") {
							if ($location.path() === "/waiting") {
								$location.path("/downloading");
							} else {
								$route.reload();
							}
						} else if (!response.hasError && state === "pause") {
							if ($location.path() === "/downloading") {
								$location.path("/waiting");
							} else {
								$route.reload();
							}
						}
					},
					gids.length > 1,
				);
			};

			$scope.retryTask = function (task) {
				ariaNgCommonService.confirm(
					"Confirm Retry",
					"Are you sure you want to retry the selected task? AriaNg will create same task after clicking OK.",
					"info",
					function () {
						$rootScope.loadPromise = aria2TaskService.retryTask(
							task.gid,
							function (response) {
								if (!response.success) {
									ariaNgCommonService.showError("Failed to retry this task.");
									return;
								}

								refreshGlobalStat(true);

								var actionAfterRetryingTask =
									ariaNgSettingService.getAfterRetryingTask();

								if (response.success && response.data) {
									if (actionAfterRetryingTask === "task-list-downloading") {
										if ($location.path() !== "/downloading") {
											$location.path("/downloading");
										} else {
											$route.reload();
										}
									} else if (actionAfterRetryingTask === "task-detail") {
										$location.path("/task/detail/" + response.data);
									} else {
										$route.reload();
									}
								}
							},
							false,
						);
					},
				);
			};

			$scope.hasRetryableTask = function () {
				return $rootScope.taskContext.hasRetryableTask();
			};

			$scope.hasCompletedTask = function () {
				return $rootScope.taskContext.hasCompletedTask();
			};

			$scope.isSelectedTaskRetryable = function () {
				var selectedTasks = $rootScope.taskContext.getSelectedTasks();

				if (selectedTasks.length < 1) {
					return false;
				}

				for (var i = 0; i < selectedTasks.length; i++) {
					if (!$rootScope.isTaskRetryable(selectedTasks[i])) {
						return false;
					}
				}

				return true;
			};

			$scope.retryTasks = function () {
				var tasks = $rootScope.taskContext.getSelectedTasks();

				if (!tasks || tasks.length < 1) {
					return;
				} else if (tasks.length === 1) {
					return $scope.retryTask(tasks[0]);
				}

				var retryableTasks = [];
				var skipCount = 0;

				for (var i = 0; i < tasks.length; i++) {
					if ($rootScope.isTaskRetryable(tasks[i])) {
						retryableTasks.push(tasks[i]);
					} else {
						skipCount++;
					}
				}

				ariaNgCommonService.confirm(
					"Confirm Retry",
					"Are you sure you want to retry the selected task? AriaNg will create same task after clicking OK.",
					"info",
					function () {
						$rootScope.loadPromise = aria2TaskService.retryTasks(
							retryableTasks,
							function (response) {
								refreshGlobalStat(true);

								ariaNgCommonService.showInfo(
									"Operation Result",
									"{successCount} tasks have been retried and {failedCount} tasks are failed.",
									function () {
										var actionAfterRetryingTask =
											ariaNgSettingService.getAfterRetryingTask();

										if (response.hasSuccess) {
											if (actionAfterRetryingTask === "task-list-downloading") {
												if ($location.path() !== "/downloading") {
													$location.path("/downloading");
												} else {
													$route.reload();
												}
											} else {
												$route.reload();
											}
										}
									},
									{
										textParams: {
											successCount: response.successCount,
											failedCount: response.failedCount,
											skipCount: skipCount,
										},
									},
								);
							},
							false,
						);
					},
					true,
				);
			};

			$scope.removeTasks = function () {
				var tasks = $rootScope.taskContext.getSelectedTasks();

				if (!tasks || tasks.length < 1) {
					return;
				}

				var removeTasks = function () {
					$rootScope.loadPromise = aria2TaskService.removeTasks(
						tasks,
						function (response) {
							if (response.hasError && tasks.length > 1) {
								ariaNgCommonService.showError("Failed to remove some task(s).");
							}

							if (!response.hasSuccess) {
								return;
							}

							refreshGlobalStat(true);

							if (!response.hasError) {
								if ($location.path() !== "/stopped") {
									$location.path("/stopped");
								} else {
									$route.reload();
								}
							}
						},
						tasks.length > 1,
					);
				};

				if (ariaNgSettingService.getConfirmTaskRemoval()) {
					ariaNgCommonService.confirm(
						"Confirm Remove",
						"Are you sure you want to remove the selected task?",
						"warning",
						removeTasks,
					);
				} else {
					removeTasks();
				}
			};

			$scope.clearStoppedTasks = function () {
				ariaNgCommonService.confirm(
					"Confirm Clear",
					"Are you sure you want to clear stopped tasks?",
					"warning",
					function () {
						$rootScope.loadPromise = aria2TaskService.clearStoppedTasks(
							function (response) {
								if (!response.success) {
									return;
								}

								refreshGlobalStat(true);

								if ($location.path() !== "/stopped") {
									$location.path("/stopped");
								} else {
									$route.reload();
								}
							},
						);
					},
				);
			};

			$scope.isAllTasksSelected = function () {
				return $rootScope.taskContext.isAllSelected();
			};

			$scope.selectAllTasks = function () {
				$rootScope.taskContext.selectAll();
			};

			$scope.selectAllFailedTasks = function () {
				$rootScope.taskContext.selectAllFailed();
			};

			$scope.selectAllCompletedTasks = function () {
				$rootScope.taskContext.selectAllCompleted();
			};

			$scope.copySelectedTasksDownloadLink = function () {
				var selectedTasks = $rootScope.taskContext.getSelectedTasks();
				var result = "";

				for (var i = 0; i < selectedTasks.length; i++) {
					if (i > 0) {
						result += "\n";
					}

					result += selectedTasks[i].singleUrl;
				}

				if (result.length > 0) {
					clipboard.copyText(result);
				}
			};

			$scope.copySelectedTasksMagnetLink = function () {
				var selectedTasks = $rootScope.taskContext.getSelectedTasks();
				var result = "";

				for (var i = 0; i < selectedTasks.length; i++) {
					if (i > 0) {
						result += "\n";
					}

					result += "magnet:?xt=urn:btih:" + selectedTasks[i].infoHash;
				}

				if (result.length > 0) {
					clipboard.copyText(result);
				}
			};

			$scope.changeDisplayOrder = function (type, autoSetReverse) {
				var taskListPageType = getTaskListPageType();
				var oldType = ariaNgCommonService.parseOrderType(
					ariaNgSettingService.getDisplayOrder(taskListPageType),
				);
				var newType = ariaNgCommonService.parseOrderType(type);

				if (autoSetReverse && newType.type === oldType.type) {
					newType.reverse = !oldType.reverse;
				}

				ariaNgSettingService.setDisplayOrder(
					newType.getValue(),
					taskListPageType,
				);
			};

			$scope.isSetDisplayOrder = function (type) {
				var taskListPageType = getTaskListPageType();
				var orderType = ariaNgCommonService.parseOrderType(
					ariaNgSettingService.getDisplayOrder(taskListPageType),
				);
				var targetType = ariaNgCommonService.parseOrderType(type);

				return orderType.equals(targetType);
			};

			$scope.showQuickSettingDialog = function (type, title) {
				$scope.quickSettingContext = {
					type: type,
					title: title,
				};
			};

			$scope.switchRpcSetting = function (setting) {
				if (setting.isDefault) {
					return;
				}

				ariaNgSettingService.setDefaultRpcSetting(setting);

				if ($location.path().indexOf("/task/detail/") === 0) {
					$rootScope.setAutoRefreshAfterPageLoad();
					$location.path("/downloading");
				} else {
					$window.location.reload();
				}
			};

			if (ariaNgSettingService.getTitleRefreshInterval() > 0) {
				pageTitleRefreshPromise = $interval(function () {
					refreshPageTitle();
				}, ariaNgSettingService.getTitleRefreshInterval());
			}

			if (ariaNgSettingService.getGlobalStatRefreshInterval() > 0) {
				globalStatRefreshPromise = $interval(function () {
					refreshGlobalStat(true);
				}, ariaNgSettingService.getGlobalStatRefreshInterval());
			}

			$scope.$on("$destroy", function () {
				if (pageTitleRefreshPromise) {
					$interval.cancel(pageTitleRefreshPromise);
				}

				if (globalStatRefreshPromise) {
					$interval.cancel(globalStatRefreshPromise);
				}
			});

			refreshGlobalStat(true, function () {
				refreshPageTitle();
			});
		},
	]);
})();

(function () {
	"use strict";

	angular.module("ariaNg").controller("NewTaskController", [
		"$rootScope",
		"$scope",
		"$location",
		"$timeout",
		"ariaNgCommonService",
		"ariaNgLogService",
		"ariaNgKeyboardService",
		"ariaNgFileService",
		"ariaNgSettingService",
		"aria2TaskService",
		"aria2SettingService",
		function (
			$rootScope,
			$scope,
			$location,
			$timeout,
			ariaNgCommonService,
			ariaNgLogService,
			ariaNgKeyboardService,
			ariaNgFileService,
			ariaNgSettingService,
			aria2TaskService,
			aria2SettingService
		) {
			var tabStatusItems = [
				{
					name: "links",
					show: true,
				},
				{
					name: "options",
					show: true,
				},
			];
			var parameters = $location.search();

			var getVisibleTabOrders = function () {
				var items = [];

				for (var i = 0; i < tabStatusItems.length; i++) {
					if (tabStatusItems[i].show) {
						items.push(tabStatusItems[i].name);
					}
				}

				return items;
			};

			var setTabItemShow = function (name, status) {
				for (var i = 0; i < tabStatusItems.length; i++) {
					if (tabStatusItems[i].name === name) {
						tabStatusItems[i].show = status;
						break;
					}
				}
			};

			var saveDownloadPath = function (options) {
				if (!options || !options.dir) {
					return;
				}

				aria2SettingService.addSettingHistory("dir", options.dir);
			};

			var getDownloadTasksByLinks = function (options) {
				var urls = ariaNgCommonService.parseUrlsFromOriginInput(
					$scope.context.urls
				);
				var tasks = [];

				if (!options) {
					options = angular.copy($scope.context.options);
				}

				for (var i = 0; i < urls.length; i++) {
					if (urls[i] === "" || urls[i].trim() === "") {
						continue;
					}

					tasks.push({
						urls: [urls[i].trim()],
						options: options,
					});
				}

				return tasks;
			};

			var downloadByLinks = function (pauseOnAdded, responseCallback) {
				var options = angular.copy($scope.context.options);
				var tasks = getDownloadTasksByLinks(options);

				saveDownloadPath(options);

				return aria2TaskService.newUriTasks(
					tasks,
					pauseOnAdded,
					responseCallback
				);
			};

			var downloadByTorrent = function (pauseOnAdded, responseCallback) {
				var options = angular.copy($scope.context.options);

				var task = {
					content: $scope.context.uploadFile.base64Content,
					options: options,
				};

				saveDownloadPath(task.options);

				return aria2TaskService.newTorrentTask(
					task,
					pauseOnAdded,
					responseCallback
				);
			};

			var downloadByMetalink = function (pauseOnAdded, responseCallback) {
				var task = {
					content: $scope.context.uploadFile.base64Content,
					options: angular.copy($scope.context.options),
				};

				saveDownloadPath(task.options);

				return aria2TaskService.newMetalinkTask(
					task,
					pauseOnAdded,
					responseCallback
				);
			};

			$scope.context = {
				currentTab: "links",
				taskType: "urls",
				urls: "",
				uploadFile: null,
				availableOptions: (function () {
					var keys = aria2SettingService.getNewTaskOptionKeys();

					return aria2SettingService.getSpecifiedOptions(keys, {
						disableRequired: true,
					});
				})(),
				globalOptions: null,
				options: {},
				optionFilter: {
					global: true,
					http: false,
					bittorrent: false,
				},
				exportCommandApiOptions: null,
			};

			if (parameters.url) {
				try {
					$scope.context.urls = ariaNgCommonService.base64UrlDecode(
						parameters.url
					);
				} catch (ex) {
					ariaNgLogService.error(
						"[NewTaskController] base64 decode error, url=" + parameters.url,
						ex
					);
				}
			}

			$scope.changeTab = function (tabName) {
				if (tabName === "options") {
					$scope.loadDefaultOption();
				}

				$scope.context.currentTab = tabName;
			};

			$rootScope.swipeActions.extendLeftSwipe = function () {
				var tabItems = getVisibleTabOrders();
				var tabIndex = tabItems.indexOf($scope.context.currentTab);

				if (tabIndex < tabItems.length - 1) {
					$scope.changeTab(tabItems[tabIndex + 1]);
					return true;
				} else {
					return false;
				}
			};

			$rootScope.swipeActions.extendRightSwipe = function () {
				var tabItems = getVisibleTabOrders();
				var tabIndex = tabItems.indexOf($scope.context.currentTab);

				if (tabIndex > 0) {
					$scope.changeTab(tabItems[tabIndex - 1]);
					return true;
				} else {
					return false;
				}
			};

			$scope.loadDefaultOption = function () {
				if ($scope.context.globalOptions) {
					return;
				}

				$rootScope.loadPromise = aria2SettingService.getGlobalOption(
					function (response) {
						if (response.success) {
							$scope.context.globalOptions = response.data;
						}
					}
				);
			};

			$scope.openTorrent = function () {
				ariaNgFileService.openFileContent(
					{
						scope: $scope,
						fileFilter: ".torrent",
						fileType: "binary",
					},
					function (result) {
						$scope.context.uploadFile = result;
						$scope.context.taskType = "torrent";
						$scope.changeTab("options");
					},
					function (error) {
						ariaNgCommonService.showError(error);
					},
					angular.element("#file-holder")
				);
			};

			$scope.openMetalink = function () {
				ariaNgFileService.openFileContent(
					{
						scope: $scope,
						fileFilter: ".meta4,.metalink",
						fileType: "binary",
					},
					function (result) {
						$scope.context.uploadFile = result;
						$scope.context.taskType = "metalink";
						$scope.changeTab("options");
					},
					function (error) {
						ariaNgCommonService.showError(error);
					},
					angular.element("#file-holder")
				);
			};

			$scope.isNewTaskValid = function () {
				if (!$scope.context.uploadFile) {
					return $scope.newTaskForm.$valid;
				}

				return true;
			};

			$scope.startDownload = function (pauseOnAdded) {
				var responseCallback = function (response) {
					if (!response.hasSuccess && !response.success) {
						return;
					}

					var firstTask = null;

					if (response.results && response.results.length > 0) {
						firstTask = response.results[0];
					} else if (response) {
						firstTask = response;
					}

					if (
						ariaNgSettingService.getAfterCreatingNewTask() === "task-detail" &&
						firstTask &&
						firstTask.data
					) {
						$location.path("/task/detail/" + firstTask.data);
					} else {
						if (pauseOnAdded) {
							$location.path("/waiting");
						} else {
							$location.path("/downloading");
						}
					}
				};

				if ($scope.context.taskType === "urls") {
					$rootScope.loadPromise = downloadByLinks(
						pauseOnAdded,
						responseCallback
					);
				} else if ($scope.context.taskType === "torrent") {
					$rootScope.loadPromise = downloadByTorrent(
						pauseOnAdded,
						responseCallback
					);
				} else if ($scope.context.taskType === "metalink") {
					$rootScope.loadPromise = downloadByMetalink(
						pauseOnAdded,
						responseCallback
					);
				}
			};

			$scope.showExportCommandAPIModal = function () {
				$scope.context.exportCommandApiOptions = {
					type: "new-task",
					data: getDownloadTasksByLinks(),
				};
			};

			$scope.setOption = function (key, value, optionStatus) {
				if (value !== "" || !aria2SettingService.isOptionKeyRequired(key)) {
					$scope.context.options[key] = value;
				} else {
					delete $scope.context.options[key];
				}

				optionStatus.setReady();
			};

			$scope.urlTextboxKeyDown = function (event) {
				if (!ariaNgSettingService.getKeyboardShortcuts()) {
					return;
				}

				if (
					ariaNgKeyboardService.isCtrlEnterPressed(event) &&
					$scope.newTaskForm.$valid
				) {
					if (event.preventDefault) {
						event.preventDefault();
					}

					$scope.startDownload();

					return false;
				}
			};

			$scope.getValidUrlsCount = function () {
				var urls = ariaNgCommonService.parseUrlsFromOriginInput(
					$scope.context.urls
				);
				return urls ? urls.length : 0;
			};

			$rootScope.loadPromise = $timeout(function () {}, 100);
		},
	]);
})();

(function () {
	"use strict";

	angular.module("ariaNg").controller("DownloadListController", [
		"$rootScope",
		"$scope",
		"$window",
		"$location",
		"$route",
		"$interval",
		"dragulaService",
		"aria2RpcErrors",
		"ariaNgCommonService",
		"ariaNgSettingService",
		"aria2TaskService",
		function (
			$rootScope,
			$scope,
			$window,
			$location,
			$route,
			$interval,
			dragulaService,
			aria2RpcErrors,
			ariaNgCommonService,
			ariaNgSettingService,
			aria2TaskService
		) {
			var location = $location.path().substring(1);
			var downloadTaskRefreshPromise = null;
			var pauseDownloadTaskRefresh = false;
			var needRequestWholeInfo = true;

			var refreshDownloadTask = function (silent) {
				if (pauseDownloadTaskRefresh) {
					return;
				}

				return aria2TaskService.getTaskList(
					location,
					needRequestWholeInfo,
					function (response) {
						if (pauseDownloadTaskRefresh) {
							return;
						}

						if (!response.success) {
							if (
								response.data.message === aria2RpcErrors.Unauthorized.message
							) {
								$interval.cancel(downloadTaskRefreshPromise);
							}

							return;
						}

						var isRequestWholeInfo = response.context.requestWholeInfo;
						var taskList = response.data;

						if (isRequestWholeInfo) {
							$rootScope.taskContext.list = taskList;
							needRequestWholeInfo = false;
						} else {
							if (
								$rootScope.taskContext.list &&
								$rootScope.taskContext.list.length > 0
							) {
								for (var i = 0; i < $rootScope.taskContext.list.length; i++) {
									var task = $rootScope.taskContext.list[i];
									delete task.verifiedLength;
									delete task.verifyIntegrityPending;
								}
							}

							if (
								ariaNgCommonService.extendArray(
									taskList,
									$rootScope.taskContext.list,
									"gid"
								)
							) {
								needRequestWholeInfo = false;
							} else {
								needRequestWholeInfo = true;
							}
						}

						if (
							$rootScope.taskContext.list &&
							$rootScope.taskContext.list.length > 0
						) {
							aria2TaskService.processDownloadTasks(
								$rootScope.taskContext.list
							);

							if (!isRequestWholeInfo) {
								var hasFullStruct = false;

								for (var i = 0; i < $rootScope.taskContext.list.length; i++) {
									var task = $rootScope.taskContext.list[i];

									if (task.hasTaskName || task.files || task.bittorrent) {
										hasFullStruct = true;
										break;
									}
								}

								if (!hasFullStruct) {
									needRequestWholeInfo = true;
									$rootScope.taskContext.list.length = 0;
									return;
								}
							}
						}

						$rootScope.taskContext.enableSelectAll =
							$rootScope.taskContext.list &&
							$rootScope.taskContext.list.length > 0;
					},
					silent
				);
			};

			$scope.getOrderType = function () {
				return ariaNgSettingService.getDisplayOrder(location);
			};

			$scope.isSupportDragTask = function () {
				if (!ariaNgSettingService.getDragAndDropTasks()) {
					return false;
				}

				var displayOrder = ariaNgCommonService.parseOrderType(
					ariaNgSettingService.getDisplayOrder(location)
				);

				return location === "waiting" && displayOrder.type === "default";
			};

			if (ariaNgSettingService.getDownloadTaskRefreshInterval() > 0) {
				downloadTaskRefreshPromise = $interval(function () {
					refreshDownloadTask(true);
				}, ariaNgSettingService.getDownloadTaskRefreshInterval());
			}

			dragulaService.options($scope, "task-list", {
				revertOnSpill: true,
				moves: function () {
					return $scope.isSupportDragTask();
				},
			});

			$scope.$on("task-list.drop-model", function (el, target, source) {
				var element = angular.element(target);
				var gid = element.attr("data-gid");
				var index = element.index();

				pauseDownloadTaskRefresh = true;

				aria2TaskService.changeTaskPosition(
					gid,
					index,
					function () {
						pauseDownloadTaskRefresh = false;
					},
					true
				);
			});

			$scope.$on("$destroy", function () {
				pauseDownloadTaskRefresh = true;

				if (downloadTaskRefreshPromise) {
					$interval.cancel(downloadTaskRefreshPromise);
				}
			});

			$rootScope.keydownActions.selectAll = function (event) {
				if (event.preventDefault) {
					event.preventDefault();
				}

				$scope.$apply(function () {
					$scope.selectAllTasks();
				});

				return false;
			};

			$rootScope.keydownActions.delete = function (event) {
				if (event.preventDefault) {
					event.preventDefault();
				}

				$scope.$apply(function () {
					$scope.removeTasks();
				});

				return false;
			};

			$rootScope.loadPromise = refreshDownloadTask(false);
		},
	]);
})();

(function () {
	"use strict";

	angular.module("ariaNg").controller("TaskDetailController", [
		"$rootScope",
		"$scope",
		"$routeParams",
		"$interval",
		"clipboard",
		"aria2RpcErrors",
		"ariaNgFileTypes",
		"ariaNgCommonService",
		"ariaNgSettingService",
		"ariaNgMonitorService",
		"aria2TaskService",
		"aria2SettingService",
		function (
			$rootScope,
			$scope,
			$routeParams,
			$interval,
			clipboard,
			aria2RpcErrors,
			ariaNgFileTypes,
			ariaNgCommonService,
			ariaNgSettingService,
			ariaNgMonitorService,
			aria2TaskService,
			aria2SettingService
		) {
			var tabStatusItems = [
				{
					name: "overview",
					show: true,
				},
				{
					name: "pieces",
					show: true,
				},
				{
					name: "filelist",
					show: true,
				},
				{
					name: "btpeers",
					show: true,
				},
			];
			var downloadTaskRefreshPromise = null;
			var pauseDownloadTaskRefresh = false;
			var currentRowTriggeredMenu = null;

			var getVisibleTabOrders = function () {
				var items = [];

				for (var i = 0; i < tabStatusItems.length; i++) {
					if (tabStatusItems[i].show) {
						items.push(tabStatusItems[i].name);
					}
				}

				return items;
			};

			var setTabItemShow = function (name, status) {
				for (var i = 0; i < tabStatusItems.length; i++) {
					if (tabStatusItems[i].name === name) {
						tabStatusItems[i].show = status;
						break;
					}
				}
			};

			var getAvailableOptions = function (status, isBittorrent) {
				var keys = aria2SettingService.getAvailableTaskOptionKeys(
					status,
					isBittorrent
				);

				return aria2SettingService.getSpecifiedOptions(keys, {
					disableRequired: true,
				});
			};

			var isShowPiecesInfo = function (task) {
				var showPiecesInfoSetting =
					ariaNgSettingService.getShowPiecesInfoInTaskDetailPage();

				if (!task || showPiecesInfoSetting === "never") {
					return false;
				}

				if (showPiecesInfoSetting === "le102400") {
					return task.numPieces <= 102400;
				} else if (showPiecesInfoSetting === "le10240") {
					return task.numPieces <= 10240;
				} else if (showPiecesInfoSetting === "le1024") {
					return task.numPieces <= 1024;
				}

				return true; // showPiecesInfoSetting === 'always'
			};

			var processTask = function (task) {
				if (!task) {
					return;
				}

				$scope.context.showPiecesInfo = isShowPiecesInfo(task);

				setTabItemShow("pieces", $scope.context.showPiecesInfo);
				setTabItemShow("btpeers", task.status === "active" && task.bittorrent);

				if (!$scope.task || $scope.task.status !== task.status) {
					$scope.context.availableOptions = getAvailableOptions(
						task.status,
						!!task.bittorrent
					);
				}

				if ($scope.task) {
					delete $scope.task.verifiedLength;
					delete $scope.task.verifyIntegrityPending;
				}

				$scope.task = ariaNgCommonService.copyObjectTo(task, $scope.task);

				$rootScope.taskContext.list = [$scope.task];
				$rootScope.taskContext.selected = {};
				$rootScope.taskContext.selected[$scope.task.gid] = true;

				ariaNgMonitorService.recordStat(task.gid, task);
			};

			var processPeers = function (peers) {
				if (!peers) {
					return;
				}

				if (
					!ariaNgCommonService.extendArray(
						peers,
						$scope.context.btPeers,
						"peerId"
					)
				) {
					$scope.context.btPeers = peers;
				}

				$scope.context.healthPercent =
					aria2TaskService.estimateHealthPercentFromPeers(
						$scope.task,
						$scope.context.btPeers
					);
			};

			var requireBtPeers = function (task) {
				return task && task.bittorrent && task.status === "active";
			};

			var refreshDownloadTask = function (silent) {
				if (pauseDownloadTaskRefresh) {
					return;
				}

				var processError = function (message) {
					$interval.cancel(downloadTaskRefreshPromise);
				};

				var includeLocalPeer = true;
				var addVirtualFileNode = true;

				if (!$scope.task) {
					return aria2TaskService.getTaskStatus(
						$routeParams.gid,
						function (response) {
							if (!response.success) {
								return processError(response.data.message);
							}

							var task = response.data;

							processTask(task);

							if (requireBtPeers(task)) {
								aria2TaskService.getBtTaskPeers(
									task,
									function (response) {
										if (response.success) {
											processPeers(response.data);
										}
									},
									silent,
									includeLocalPeer
								);
							}
						},
						silent,
						addVirtualFileNode
					);
				} else {
					return aria2TaskService.getTaskStatusAndBtPeers(
						$routeParams.gid,
						function (response) {
							if (!response.success) {
								return processError(response.data.message);
							}

							processTask(response.task);
							processPeers(response.peers);
						},
						silent,
						requireBtPeers($scope.task),
						includeLocalPeer,
						addVirtualFileNode
					);
				}
			};

			var setSelectFiles = function (silent) {
				if (!$scope.task || !$scope.task.files) {
					return;
				}

				var gid = $scope.task.gid;
				var selectedFileIndex = [];

				for (var i = 0; i < $scope.task.files.length; i++) {
					var file = $scope.task.files[i];

					if (file && file.selected && !file.isDir) {
						selectedFileIndex.push(file.index);
					}
				}

				pauseDownloadTaskRefresh = true;

				return aria2TaskService.selectTaskFile(
					gid,
					selectedFileIndex,
					function (response) {
						pauseDownloadTaskRefresh = false;

						if (response.success) {
							refreshDownloadTask(false);
						}
					},
					silent
				);
			};

			var setSelectedNode = function (node, value) {
				if (!node) {
					return;
				}

				if (node.files && node.files.length) {
					for (var i = 0; i < node.files.length; i++) {
						var fileNode = node.files[i];
						fileNode.selected = value;
					}
				}

				if (node.subDirs && node.subDirs.length) {
					for (var i = 0; i < node.subDirs.length; i++) {
						var dirNode = node.subDirs[i];
						setSelectedNode(dirNode, value);
					}
				}

				node.selected = value;
				node.partialSelected = false;
			};

			var updateDirNodeSelectedStatus = function (node) {
				if (!node) {
					return;
				}

				var selectedSubNodesCount = 0;
				var partitalSelectedSubNodesCount = 0;

				if (node.files && node.files.length) {
					for (var i = 0; i < node.files.length; i++) {
						var fileNode = node.files[i];
						selectedSubNodesCount += fileNode.selected ? 1 : 0;
					}
				}

				if (node.subDirs && node.subDirs.length) {
					for (var i = 0; i < node.subDirs.length; i++) {
						var dirNode = node.subDirs[i];
						updateDirNodeSelectedStatus(dirNode);
						selectedSubNodesCount += dirNode.selected ? 1 : 0;
						partitalSelectedSubNodesCount += dirNode.partialSelected ? 1 : 0;
					}
				}

				node.selected =
					selectedSubNodesCount > 0 &&
					selectedSubNodesCount === node.subDirs.length + node.files.length;
				node.partialSelected =
					(selectedSubNodesCount > 0 &&
						selectedSubNodesCount < node.subDirs.length + node.files.length) ||
					partitalSelectedSubNodesCount > 0;
			};

			var updateAllDirNodesSelectedStatus = function () {
				if (!$scope.task || !$scope.task.multiDir) {
					return;
				}

				for (var i = 0; i < $scope.task.files.length; i++) {
					var node = $scope.task.files[i];

					if (!node.isDir) {
						continue;
					}

					updateDirNodeSelectedStatus(node);
				}
			};

			$scope.context = {
				currentTab: "overview",
				isEnableSpeedChart:
					ariaNgSettingService.getDownloadTaskRefreshInterval() > 0,
				showPiecesInfo:
					ariaNgSettingService.getShowPiecesInfoInTaskDetailPage() !== "never",
				showChooseFilesToolbar: false,
				fileExtensions: [],
				collapsedDirs: {},
				btPeers: [],
				healthPercent: 0,
				collapseTrackers: true,
				statusData: ariaNgMonitorService.getEmptyStatsData($routeParams.gid),
				availableOptions: [],
				options: [],
			};

			$scope.changeTab = function (tabName) {
				if (tabName === "settings") {
					$scope.loadTaskOption($scope.task);
				}

				$scope.context.currentTab = tabName;
			};

			$rootScope.swipeActions.extendLeftSwipe = function () {
				var tabItems = getVisibleTabOrders();
				var tabIndex = tabItems.indexOf($scope.context.currentTab);

				if (tabIndex < tabItems.length - 1) {
					$scope.changeTab(tabItems[tabIndex + 1]);
					return true;
				} else {
					return false;
				}
			};

			$rootScope.swipeActions.extendRightSwipe = function () {
				var tabItems = getVisibleTabOrders();
				var tabIndex = tabItems.indexOf($scope.context.currentTab);

				if (tabIndex > 0) {
					$scope.changeTab(tabItems[tabIndex - 1]);
					return true;
				} else {
					return false;
				}
			};

			$scope.changeFileListDisplayOrder = function (type, autoSetReverse) {
				if ($scope.task && $scope.task.multiDir) {
					return;
				}

				var oldType = ariaNgCommonService.parseOrderType(
					ariaNgSettingService.getFileListDisplayOrder()
				);
				var newType = ariaNgCommonService.parseOrderType(type);

				if (autoSetReverse && newType.type === oldType.type) {
					newType.reverse = !oldType.reverse;
				}

				ariaNgSettingService.setFileListDisplayOrder(newType.getValue());
			};

			$scope.isSetFileListDisplayOrder = function (type) {
				var orderType = ariaNgCommonService.parseOrderType(
					ariaNgSettingService.getFileListDisplayOrder()
				);
				var targetType = ariaNgCommonService.parseOrderType(type);

				return orderType.equals(targetType);
			};

			$scope.getFileListOrderType = function () {
				if ($scope.task && $scope.task.multiDir) {
					return null;
				}

				return ariaNgSettingService.getFileListDisplayOrder();
			};

			$scope.showChooseFilesToolbar = function () {
				if (!$scope.context.showChooseFilesToolbar) {
					pauseDownloadTaskRefresh = true;
					$scope.context.showChooseFilesToolbar = true;
				} else {
					$scope.cancelChooseFiles();
				}
			};

			$scope.isAnyFileSelected = function () {
				if (!$scope.task || !$scope.task.files) {
					return false;
				}

				for (var i = 0; i < $scope.task.files.length; i++) {
					var file = $scope.task.files[i];

					if (!file.isDir && file.selected) {
						return true;
					}
				}

				return false;
			};

			$scope.isAllFileSelected = function () {
				if (!$scope.task || !$scope.task.files) {
					return false;
				}

				for (var i = 0; i < $scope.task.files.length; i++) {
					var file = $scope.task.files[i];

					if (!file.isDir && !file.selected) {
						return false;
					}
				}

				return true;
			};

			$scope.selectFiles = function (type) {
				if (!$scope.task || !$scope.task.files) {
					return;
				}

				if (type === "auto") {
					if ($scope.isAllFileSelected()) {
						type = "none";
					} else {
						type = "all";
					}
				}

				for (var i = 0; i < $scope.task.files.length; i++) {
					var file = $scope.task.files[i];

					if (file.isDir) {
						continue;
					}

					if (type === "all") {
						file.selected = true;
					} else if (type === "none") {
						file.selected = false;
					} else if (type === "reverse") {
						file.selected = !file.selected;
					}
				}

				updateAllDirNodesSelectedStatus();
			};

			$scope.chooseSpecifiedFiles = function (type) {
				if (!$scope.task || !$scope.task.files || !ariaNgFileTypes[type]) {
					return;
				}

				var files = $scope.task.files;
				var extensions = ariaNgFileTypes[type].extensions;
				var fileIndexes = [];
				var isAllSelected = true;

				for (var i = 0; i < files.length; i++) {
					var file = files[i];

					if (file.isDir) {
						continue;
					}

					var extension = ariaNgCommonService.getFileExtension(file.fileName);

					if (extension) {
						extension = extension.toLowerCase();
					}

					if (extensions.indexOf(extension) >= 0) {
						fileIndexes.push(i);

						if (!file.selected) {
							isAllSelected = false;
						}
					}
				}

				for (var i = 0; i < fileIndexes.length; i++) {
					var index = fileIndexes[i];
					var file = files[index];

					if (file && !file.isDir) {
						file.selected = !isAllSelected;
					}
				}

				updateAllDirNodesSelectedStatus();
			};

			$scope.saveChoosedFiles = function () {
				if ($scope.context.showChooseFilesToolbar) {
					$rootScope.loadPromise = setSelectFiles(false);
					$scope.context.showChooseFilesToolbar = false;
				}
			};

			$scope.cancelChooseFiles = function () {
				if ($scope.context.showChooseFilesToolbar) {
					pauseDownloadTaskRefresh = false;
					refreshDownloadTask(true);
					$scope.context.showChooseFilesToolbar = false;
				}
			};

			$scope.showCustomChooseFileModal = function () {
				if (!$scope.task || !$scope.task.files) {
					return;
				}

				var files = $scope.task.files;
				var extensionsMap = {};

				for (var i = 0; i < files.length; i++) {
					var file = files[i];

					if (file.isDir) {
						continue;
					}

					var extension = ariaNgCommonService.getFileExtension(file.fileName);

					if (extension) {
						extension = extension.toLowerCase();
					}

					var extensionInfo = extensionsMap[extension];

					if (!extensionInfo) {
						var extensionName = extension;

						if (extensionName.length > 0 && extensionName.charAt(0) === ".") {
							extensionName = extensionName.substring(1);
						}

						extensionInfo = {
							extension: extensionName,
							classified: false,
							selected: false,
							selectedCount: 0,
							unSelectedCount: 0,
						};

						extensionsMap[extension] = extensionInfo;
					}

					if (file.selected) {
						extensionInfo.selected = true;
						extensionInfo.selectedCount++;
					} else {
						extensionInfo.unSelectedCount++;
					}
				}

				var allClassifiedExtensions = {};

				for (var type in ariaNgFileTypes) {
					if (!ariaNgFileTypes.hasOwnProperty(type)) {
						continue;
					}

					var extensionTypeName = ariaNgFileTypes[type].name;
					var allExtensions = ariaNgFileTypes[type].extensions;
					var extensions = [];

					for (var i = 0; i < allExtensions.length; i++) {
						var extension = allExtensions[i];
						var extensionInfo = extensionsMap[extension];

						if (extensionInfo) {
							extensionInfo.classified = true;
							extensions.push(extensionInfo);
						}
					}

					if (extensions.length > 0) {
						allClassifiedExtensions[type] = {
							name: extensionTypeName,
							extensions: extensions,
						};
					}
				}

				var unClassifiedExtensions = [];

				for (var extension in extensionsMap) {
					if (!extensionsMap.hasOwnProperty(extension)) {
						continue;
					}

					var extensionInfo = extensionsMap[extension];

					if (!extensionInfo.classified) {
						unClassifiedExtensions.push(extensionInfo);
					}
				}

				if (unClassifiedExtensions.length > 0) {
					allClassifiedExtensions.other = {
						name: "Other",
						extensions: unClassifiedExtensions,
					};
				}

				$scope.context.fileExtensions = allClassifiedExtensions;
				angular.element("#custom-choose-file-modal").modal();
			};

			$scope.setSelectedExtension = function (selectedExtension, selected) {
				if (!$scope.task || !$scope.task.files) {
					return;
				}

				var files = $scope.task.files;

				for (var i = 0; i < files.length; i++) {
					var file = files[i];

					if (file.isDir) {
						continue;
					}

					var extension = ariaNgCommonService.getFileExtension(file.fileName);

					if (extension) {
						extension = extension.toLowerCase();
					}

					if (extension !== "." + selectedExtension) {
						continue;
					}

					file.selected = selected;
				}

				updateAllDirNodesSelectedStatus();
			};

			$("#custom-choose-file-modal").on("hide.bs.modal", function (e) {
				$scope.context.fileExtensions = null;
			});

			$scope.setSelectedFile = function (updateNodeSelectedStatus) {
				if (updateNodeSelectedStatus) {
					updateAllDirNodesSelectedStatus();
				}

				if (!$scope.context.showChooseFilesToolbar) {
					setSelectFiles(true);
				}
			};

			$scope.collapseDir = function (dirNode, newValue, forceRecurse) {
				var nodePath = dirNode.nodePath;

				if (angular.isUndefined(newValue)) {
					newValue = !$scope.context.collapsedDirs[nodePath];
				}

				if (newValue || forceRecurse) {
					for (var i = 0; i < dirNode.subDirs.length; i++) {
						$scope.collapseDir(dirNode.subDirs[i], newValue);
					}
				}

				if (nodePath) {
					$scope.context.collapsedDirs[nodePath] = newValue;
				}
			};

			$scope.collapseAllDirs = function (newValue) {
				if (!$scope.task || !$scope.task.files) {
					return;
				}

				for (var i = 0; i < $scope.task.files.length; i++) {
					var node = $scope.task.files[i];

					if (!node.isDir) {
						continue;
					}

					$scope.collapseDir(node, newValue, true);
				}
			};

			$scope.setSelectedNode = function (dirNode) {
				setSelectedNode(dirNode, dirNode.selected);
				updateAllDirNodesSelectedStatus();

				if (!$scope.context.showChooseFilesToolbar) {
					$scope.setSelectedFile(false);
				}
			};

			$scope.changePeerListDisplayOrder = function (type, autoSetReverse) {
				var oldType = ariaNgCommonService.parseOrderType(
					ariaNgSettingService.getPeerListDisplayOrder()
				);
				var newType = ariaNgCommonService.parseOrderType(type);

				if (autoSetReverse && newType.type === oldType.type) {
					newType.reverse = !oldType.reverse;
				}

				ariaNgSettingService.setPeerListDisplayOrder(newType.getValue());
			};

			$scope.isSetPeerListDisplayOrder = function (type) {
				var orderType = ariaNgCommonService.parseOrderType(
					ariaNgSettingService.getPeerListDisplayOrder()
				);
				var targetType = ariaNgCommonService.parseOrderType(type);

				return orderType.equals(targetType);
			};

			$scope.getPeerListOrderType = function () {
				return ariaNgSettingService.getPeerListDisplayOrder();
			};

			$scope.loadTaskOption = function (task) {
				$rootScope.loadPromise = aria2TaskService.getTaskOptions(
					task.gid,
					function (response) {
						if (response.success) {
							$scope.context.options = response.data;
						}
					}
				);
			};

			$scope.setOption = function (key, value, optionStatus) {
				return aria2TaskService.setTaskOption(
					$scope.task.gid,
					key,
					value,
					function (response) {
						if (response.success && response.data === "OK") {
							optionStatus.setSuccess();
						} else {
							optionStatus.setFailed(response.data.message);
						}
					},
					true
				);
			};

			$scope.copySelectedRowText = function () {
				if (!currentRowTriggeredMenu) {
					return;
				}

				var name = currentRowTriggeredMenu
					.find(".setting-key > span")
					.text()
					.trim();
				var value = "";

				currentRowTriggeredMenu
					.find(".setting-value > span")
					.each(function (i, element) {
						if (i > 0) {
							value += "\n";
						}

						value += angular.element(element).text().trim();
					});

				if (ariaNgSettingService.getIncludePrefixWhenCopyingFromTaskDetails()) {
					var info = name + ": " + value;
					clipboard.copyText(info);
				} else {
					clipboard.copyText(value);
				}
			};

			if (ariaNgSettingService.getDownloadTaskRefreshInterval() > 0) {
				downloadTaskRefreshPromise = $interval(function () {
					if (
						$scope.task &&
						($scope.task.status === "complete" ||
							$scope.task.status === "error" ||
							$scope.task.status === "removed")
					) {
						$interval.cancel(downloadTaskRefreshPromise);
						return;
					}

					refreshDownloadTask(true);
				}, ariaNgSettingService.getDownloadTaskRefreshInterval());
			}

			$scope.$on("$destroy", function () {
				if (downloadTaskRefreshPromise) {
					$interval.cancel(downloadTaskRefreshPromise);
				}
			});

			$scope.onOverviewMouseDown = function () {
				angular
					.element('#overview-items .row[contextmenu-bind!="true"]')
					.contextmenu({
						target: "#task-overview-contextmenu",
						before: function (e, context) {
							currentRowTriggeredMenu = context;
						},
					})
					.attr("contextmenu-bind", "true");
			};

			angular
				.element("#task-overview-contextmenu")
				.on("hide.bs.context", function () {
					currentRowTriggeredMenu = null;
				});

			$rootScope.loadPromise = refreshDownloadTask(false);
		},
	]);
})();

(function () {
	"use strict";

	angular.module("ariaNg").controller("AriaNgSettingsController", [
		"$rootScope",
		"$scope",
		"$routeParams",
		"$window",
		"$interval",
		"$timeout",
		"$filter",
		"clipboard",
		"ariaNgLanguages",
		"ariaNgCommonService",
		"ariaNgVersionService",
		"ariaNgKeyboardService",
		"ariaNgNotificationService",
		"ariaNgLocalizationService",
		"ariaNgLogService",
		"ariaNgFileService",
		"ariaNgSettingService",
		"ariaNgMonitorService",
		"ariaNgTitleService",
		"aria2SettingService",
		function (
			$rootScope,
			$scope,
			$routeParams,
			$window,
			$interval,
			$timeout,
			$filter,
			clipboard,
			ariaNgLanguages,
			ariaNgCommonService,
			ariaNgVersionService,
			ariaNgKeyboardService,
			ariaNgNotificationService,
			ariaNgLocalizationService,
			ariaNgLogService,
			ariaNgFileService,
			ariaNgSettingService,
			ariaNgMonitorService,
			ariaNgTitleService,
			aria2SettingService
		) {
			var extendType = $routeParams.extendType;
			var lastRefreshPageNotification = null;

			var getFinalTitle = function () {
				return ariaNgTitleService.getFinalTitleByGlobalStat({
					globalStat: ariaNgMonitorService.getCurrentGlobalStat(),
					currentRpcProfile: getCurrentRPCProfile(),
				});
			};

			var getCurrentRPCProfile = function () {
				if (
					!$scope.context ||
					!$scope.context.rpcSettings ||
					$scope.context.rpcSettings.length < 1
				) {
					return null;
				}

				for (var i = 0; i < $scope.context.rpcSettings.length; i++) {
					var rpcSetting = $scope.context.rpcSettings[i];
					if (rpcSetting.isDefault) {
						return rpcSetting;
					}
				}

				return null;
			};

			var setNeedRefreshPage = function () {
				if (lastRefreshPageNotification) {
					return;
				}

				lastRefreshPageNotification = ariaNgNotificationService.notifyInPage(
					"",
					"Configuration has been modified, please reload the page for the changes to take effect.",
					{
						delay: false,
						type: "info",
						templateUrl: "views/notification-reloadable.html",
						onClose: function () {
							lastRefreshPageNotification = null;
						},
					}
				);
			};

			$scope.context = {
				currentTab: "global",
				ariaNgVersion: ariaNgVersionService.getBuildVersion(),
				buildCommit: ariaNgVersionService.getBuildCommit(),
				languages: (function () {
					var languages = [];

					for (var langName in ariaNgLanguages) {
						if (!ariaNgLanguages.hasOwnProperty(langName)) {
							continue;
						}

						var language = ariaNgLanguages[langName];

						languages.push({
							type: langName,
							name: language.name,
							displayName: language.displayName,
						});
					}

					languages.sort(function (lang1, lang2) {
						return String.naturalCompare(lang1.type, lang2.type);
					});

					return languages;
				})(),
				titlePreview: getFinalTitle(),
				availableTime: ariaNgCommonService.getTimeOptions(
					[1000, 2000, 3000, 5000, 10000, 30000, 60000],
					true
				),
				trueFalseOptions: [
					{ name: "Enabled", value: true },
					{ name: "Disabled", value: false },
				],
				showRpcSecret: false,
				isInsecureProtocolDisabled:
					ariaNgSettingService.isInsecureProtocolDisabled(),
				settings: ariaNgSettingService.getAllOptions(),
				sessionSettings: ariaNgSettingService.getAllSessionOptions(),
				rpcSettings: ariaNgSettingService.getAllRpcSettings(),
				isMacKeyboardLike: ariaNgKeyboardService.isMacKeyboardLike(),
				isSupportReconnect: aria2SettingService.canReconnect(),
				isSupportBlob: ariaNgFileService.isSupportBlob(),
				isSupportDarkMode: ariaNgSettingService.isBrowserSupportDarkMode(),
				importSettings: null,
				exportSettings: null,
				exportSettingsCopied: false,
				exportCommandApiOptions: null,
			};

			$scope.context.titlePreview = getFinalTitle();
			$scope.context.showDebugMode =
				$scope.context.sessionSettings.debugMode || extendType === "debug";

			$scope.changeGlobalTab = function () {
				$scope.context.currentTab = "global";
			};

			$scope.isCurrentGlobalTab = function () {
				return $scope.context.currentTab === "global";
			};

			$scope.changeRpcTab = function (rpcIndex) {
				$scope.context.currentTab = "rpc" + rpcIndex;
			};

			$scope.isCurrentRpcTab = function (rpcIndex) {
				return $scope.context.currentTab === "rpc" + rpcIndex;
			};

			$scope.getCurrentRpcTabIndex = function () {
				if ($scope.isCurrentGlobalTab()) {
					return -1;
				}

				return parseInt($scope.context.currentTab.substring(3));
			};

			$scope.updateTitlePreview = function () {
				$scope.context.titlePreview = getFinalTitle();
			};

			$rootScope.swipeActions.extendLeftSwipe = function () {
				var tabIndex = -1;

				if (!$scope.isCurrentGlobalTab()) {
					tabIndex = parseInt($scope.getCurrentRpcTabIndex());
				}

				if (tabIndex < $scope.context.rpcSettings.length - 1) {
					$scope.changeRpcTab(tabIndex + 1);
					return true;
				} else {
					return false;
				}
			};

			$rootScope.swipeActions.extendRightSwipe = function () {
				var tabIndex = -1;

				if (!$scope.isCurrentGlobalTab()) {
					tabIndex = parseInt($scope.getCurrentRpcTabIndex());
				}

				if (tabIndex > 0) {
					$scope.changeRpcTab(tabIndex - 1);
					return true;
				} else if (tabIndex === 0) {
					$scope.changeGlobalTab();
					return true;
				} else {
					return false;
				}
			};

			$scope.isSupportNotification = function () {
				return (
					ariaNgNotificationService.isSupportBrowserNotification() &&
					ariaNgSettingService.isCurrentRpcUseWebSocket(
						$scope.context.settings.protocol
					)
				);
			};

			$scope.setLanguage = function (value) {
				if (ariaNgSettingService.setLanguage(value)) {
					ariaNgLocalizationService.applyLanguage(value);
				}

				$scope.updateTitlePreview();
			};

			$scope.setTheme = function (value) {
				ariaNgSettingService.setTheme(value);
				$rootScope.setTheme(value);
			};

			$scope.setDebugMode = function (value) {
				ariaNgSettingService.setDebugMode(value);
			};

			$scope.setTitle = function (value) {
				ariaNgSettingService.setTitle(value);
			};

			$scope.setEnableBrowserNotification = function (value) {
				ariaNgSettingService.setBrowserNotification(value);

				if (value && !ariaNgNotificationService.hasBrowserPermission()) {
					ariaNgNotificationService.requestBrowserPermission(function (result) {
						if (!result.granted) {
							$scope.context.settings.browserNotification = false;
							ariaNgCommonService.showError(
								"You have disabled notification in your browser. You should change your browser's settings before you enable this function."
							);
						}
					});
				}
			};

			$scope.setBrowserNotificationSound = function (value) {
				ariaNgSettingService.setBrowserNotificationSound(value);
			};

			$scope.setBrowserNotificationFrequency = function (value) {
				ariaNgSettingService.setBrowserNotificationFrequency(value);
			};

			$scope.setWebSocketReconnectInterval = function (value) {
				setNeedRefreshPage();
				ariaNgSettingService.setWebSocketReconnectInterval(value);
			};

			$scope.setTitleRefreshInterval = function (value) {
				setNeedRefreshPage();
				ariaNgSettingService.setTitleRefreshInterval(value);
			};

			$scope.setGlobalStatRefreshInterval = function (value) {
				setNeedRefreshPage();
				ariaNgSettingService.setGlobalStatRefreshInterval(value);
			};

			$scope.setDownloadTaskRefreshInterval = function (value) {
				setNeedRefreshPage();
				ariaNgSettingService.setDownloadTaskRefreshInterval(value);
			};

			$scope.setRPCListDisplayOrder = function (value) {
				setNeedRefreshPage();
				ariaNgSettingService.setRPCListDisplayOrder(value);
			};

			$scope.setTaskListIndependentDisplayOrder = function (value) {
				ariaNgSettingService.setTaskListIndependentDisplayOrder(value);
			};

			$scope.setKeyboardShortcuts = function (value) {
				ariaNgSettingService.setKeyboardShortcuts(value);
			};

			$scope.setSwipeGesture = function (value) {
				ariaNgSettingService.setSwipeGesture(value);
			};

			$scope.setDragAndDropTasks = function (value) {
				ariaNgSettingService.setDragAndDropTasks(value);
			};

			$scope.setAfterCreatingNewTask = function (value) {
				ariaNgSettingService.setAfterCreatingNewTask(value);
			};

			$scope.setRemoveOldTaskAfterRetrying = function (value) {
				ariaNgSettingService.setRemoveOldTaskAfterRetrying(value);
			};

			$scope.setConfirmTaskRemoval = function (value) {
				ariaNgSettingService.setConfirmTaskRemoval(value);
			};

			$scope.setIncludePrefixWhenCopyingFromTaskDetails = function (value) {
				ariaNgSettingService.setIncludePrefixWhenCopyingFromTaskDetails(value);
			};

			$scope.setShowPiecesInfoInTaskDetailPage = function (value) {
				ariaNgSettingService.setShowPiecesInfoInTaskDetailPage(value);
			};

			$scope.setAfterRetryingTask = function (value) {
				ariaNgSettingService.setAfterRetryingTask(value);
			};

			$scope.showImportSettingsModal = function () {
				$scope.context.importSettings = null;
				angular.element("#import-settings-modal").modal();
			};

			$("#import-settings-modal").on("hide.bs.modal", function (e) {
				$scope.context.importSettings = null;
			});

			$scope.openAriaNgConfigFile = function () {
				ariaNgFileService.openFileContent(
					{
						scope: $scope,
						fileFilter: ".json",
						fileType: "text",
					},
					function (result) {
						$scope.context.importSettings = result.content;
					},
					function (error) {
						ariaNgCommonService.showError(error);
					},
					angular.element("#import-file-holder")
				);
			};

			$scope.importSettings = function (settings) {
				var settingsObj = null;

				try {
					settingsObj = JSON.parse(settings);
				} catch (e) {
					ariaNgLogService.error(
						"[AriaNgSettingsController.importSettings] parse settings json error",
						e
					);
					ariaNgCommonService.showError("Invalid settings data format!");
					return;
				}

				if (!angular.isObject(settingsObj) || angular.isArray(settingsObj)) {
					ariaNgLogService.error(
						"[AriaNgSettingsController.importSettings] settings json is not object"
					);
					ariaNgCommonService.showError("Invalid settings data format!");
					return;
				}

				if (settingsObj) {
					ariaNgCommonService.confirm(
						"Confirm Import",
						"Are you sure you want to import all settings?",
						"warning",
						function () {
							ariaNgSettingService.importAllOptions(settingsObj);
							$window.location.reload();
						}
					);
				}
			};

			$scope.showExportSettingsModal = function () {
				$scope.context.exportSettings = $filter("json")(
					ariaNgSettingService.exportAllOptions()
				);
				$scope.context.exportSettingsCopied = false;
				angular.element("#export-settings-modal").modal();
			};

			$("#export-settings-modal").on("hide.bs.modal", function (e) {
				$scope.context.exportSettings = null;
				$scope.context.exportSettingsCopied = false;
			});

			$scope.copyExportSettings = function () {
				clipboard.copyText($scope.context.exportSettings, {
					container: angular.element("#export-settings-modal")[0],
				});
				$scope.context.exportSettingsCopied = true;
			};

			$scope.addNewRpcSetting = function () {
				setNeedRefreshPage();

				var newRpcSetting = ariaNgSettingService.addNewRpcSetting();
				$scope.context.rpcSettings.push(newRpcSetting);

				$scope.changeRpcTab($scope.context.rpcSettings.length - 1);
			};

			$scope.updateRpcSetting = function (setting, field) {
				setNeedRefreshPage();
				ariaNgSettingService.updateRpcSetting(setting, field);
			};

			$scope.removeRpcSetting = function (setting) {
				var rpcName = setting.rpcAlias
					? setting.rpcAlias
					: setting.rpcHost + ":" + setting.rpcPort;

				ariaNgCommonService.confirm(
					"Confirm Remove",
					'Are you sure you want to remove rpc setting "{rpcName}"?',
					"warning",
					function () {
						setNeedRefreshPage();

						var currentIndex = $scope.getCurrentRpcTabIndex();
						var index = $scope.context.rpcSettings.indexOf(setting);
						ariaNgSettingService.removeRpcSetting(setting);
						$scope.context.rpcSettings.splice(index, 1);

						if (currentIndex >= $scope.context.rpcSettings.length) {
							$scope.changeRpcTab($scope.context.rpcSettings.length - 1);
						} else if (currentIndex <= 0 || currentIndex <= index) {
							// Do Nothing
						} else {
							// currentIndex > index
							$scope.changeRpcTab(currentIndex - 1);
						}
					},
					false,
					{
						textParams: {
							rpcName: rpcName,
						},
					}
				);
			};

			$scope.showExportCommandAPIModal = function (setting) {
				$scope.context.exportCommandApiOptions = {
					type: "setting",
					data: setting,
				};
			};

			$scope.setDefaultRpcSetting = function (setting) {
				if (setting.isDefault) {
					return;
				}

				ariaNgSettingService.setDefaultRpcSetting(setting);
				$window.location.reload();
			};

			$scope.resetSettings = function () {
				ariaNgCommonService.confirm(
					"Confirm Reset",
					"Are you sure you want to reset all settings?",
					"warning",
					function () {
						ariaNgSettingService.resetSettings();
						$window.location.reload();
					}
				);
			};

			$scope.clearHistory = function () {
				ariaNgCommonService.confirm(
					"Confirm Clear",
					"Are you sure you want to clear all settings history?",
					"warning",
					function () {
						aria2SettingService.clearSettingsHistorys();
						$window.location.reload();
					}
				);
			};

			angular.element('[data-toggle="popover"]').popover();

			$rootScope.loadPromise = $timeout(function () {}, 100);
		},
	]);
})();

(function () {
	"use strict";

	angular.module("ariaNg").controller("Aria2SettingsController", [
		"$rootScope",
		"$scope",
		"$location",
		"ariaNgConstants",
		"ariaNgCommonService",
		"aria2SettingService",
		function (
			$rootScope,
			$scope,
			$location,
			ariaNgConstants,
			ariaNgCommonService,
			aria2SettingService
		) {
			var location = $location
				.path()
				.substring($location.path().lastIndexOf("/") + 1);

			$scope.context = {
				availableOptions: (function (type) {
					var keys = aria2SettingService.getAvailableGlobalOptionsKeys(type);

					if (!keys) {
						ariaNgCommonService.showError("Type is illegal!");
						return;
					}

					return aria2SettingService.getSpecifiedOptions(keys);
				})(location),
				globalOptions: [],
			};

			$scope.setGlobalOption = function (key, value, optionStatus) {
				return aria2SettingService.setGlobalOption(
					key,
					value,
					function (response) {
						if (response.success && response.data === "OK") {
							optionStatus.setSuccess();
						} else {
							optionStatus.setFailed(response.data.message);
						}
					},
					true
				);
			};

			$rootScope.loadPromise = (function () {
				return aria2SettingService.getGlobalOption(function (response) {
					if (response.success) {
						$scope.context.globalOptions = response.data;
					}
				});
			})();
		},
	]);
})();

(function () {
	"use strict";

	angular.module("ariaNg").controller("Aria2StatusController", [
		"$rootScope",
		"$scope",
		"$timeout",
		"ariaNgCommonService",
		"ariaNgSettingService",
		"aria2SettingService",
		function (
			$rootScope,
			$scope,
			$timeout,
			ariaNgCommonService,
			ariaNgSettingService,
			aria2SettingService
		) {
			$scope.context = {
				host: ariaNgSettingService.getCurrentRpcUrl(),
				serverStatus: null,
				isSupportReconnect: aria2SettingService.canReconnect(),
			};

			$scope.reconnect = function () {
				if (
					!$scope.context.isSupportReconnect ||
					($rootScope.taskContext.rpcStatus !== "Disconnected" &&
						$rootScope.taskContext.rpcStatus !== "Waiting to reconnect")
				) {
					return;
				}

				aria2SettingService.reconnect();
			};

			$scope.saveSession = function () {
				return aria2SettingService.saveSession(function (response) {
					if (response.success && response.data === "OK") {
						ariaNgCommonService.showOperationSucceeded(
							"Session has been saved successfully."
						);
					}
				});
			};

			$scope.shutdown = function () {
				ariaNgCommonService.confirm(
					"Confirm Shutdown",
					"Are you sure you want to shutdown aria2?",
					"warning",
					function (status) {
						return aria2SettingService.shutdown(function (response) {
							if (response.success && response.data === "OK") {
								ariaNgCommonService.showOperationSucceeded(
									"Aria2 has been shutdown successfully."
								);
							}
						});
					},
					true
				);
			};

			$rootScope.$watch("taskContext.rpcStatus", function (value) {
				if (value === "Connected") {
					aria2SettingService.getAria2Status(function (response) {
						if (response.success) {
							$scope.context.serverStatus = response.data;
						}
					});
				} else {
					$scope.context.serverStatus = null;
				}
			});

			$rootScope.loadPromise = $timeout(function () {}, 100);
		},
	]);
})();

